class GmailService {
  private gmail: gmail_v1.Gmail;

  async fetchEmails(userId: string): Promise<Email[]> {
    // Fetch unread inbox emails
    const unreadQuery = 'is:unread in:inbox';
    // Fetch Notify labeled emails
    const notifyQuery = 'label:Notify';
    // Fetch Action Item labeled emails
    const actionQuery = 'label:Action-Item';

    const results = await Promise.all([
      this.gmail.users.messages.list({ userId: 'me', q: unreadQuery }),
      this.gmail.users.messages.list({ userId: 'me', q: notifyQuery }),
      this.gmail.users.messages.list({ userId: 'me', q: actionQuery })
    ]);

    // Deduplicate and fetch full message details
    return this.processEmails(results);
  }

  async toggleReadStatus(messageId: string, markAsRead: boolean) {
    const request = markAsRead 
      ? { removeLabelIds: ['UNREAD'] }
      : { addLabelIds: ['UNREAD'] };
    return this.gmail.users.messages.modify({ userId: 'me', id: messageId, requestBody: request });
  }

  async toggleLabel(messageId: string, labelName: string, add: boolean) {
    const labels = await this.gmail.users.labels.list({ userId: 'me' });
    const label = labels.data.labels.find(l => l.name === labelName);
    const request = add 
      ? { addLabelIds: [label.id] }
      : { removeLabelIds: [label.id] };
    return this.gmail.users.messages.modify({ userId: 'me', id: messageId, requestBody: request });
  }
}
```

