const EmailActions: React.FC<EmailActionsProps> = ({ emailId, isUnread, hasNotifyLabel, hasActionItemLabel }) => {
  const queryClient = useQueryClient();

  const toggleReadMutation = useMutation(
    (markAsRead: boolean) => api.toggleReadStatus(emailId, markAsRead),
    {
      onMutate: async (markAsRead) => {
        // Optimistic update
        await queryClient.cancelQueries(['emails']);
        const previous = queryClient.getQueryData(['emails']);
        queryClient.setQueryData(['emails'], old => 
          updateEmailInList(old, emailId, { isUnread: !markAsRead })
        );
        return { previous };
      },
      onError: (err, variables, context) => {
        queryClient.setQueryData(['emails'], context.previous);
      },
      onSettled: () => {
        queryClient.invalidateQueries(['emails']);
      }
    }
  );

  return (
    <div className="email-actions">
      <button 
        onClick={() => toggleReadMutation.mutate(!isUnread)}
        title={isUnread ? 'Mark as Read' : 'Mark as Unread'}
      >
        {isUnread ? '📖' : '📕'}
      </button>
      <button 
        onClick={() => toggleLabelMutation.mutate({ label: 'Notify', add: !hasNotifyLabel })}
        className={hasNotifyLabel ? 'active' : ''}
      >
        🔔
      </button>
      <button 
        onClick={() => toggleLabelMutation.mutate({ label: 'Action Item', add: !hasActionItemLabel })}
        className={hasActionItemLabel ? 'active' : ''}
      >
        📌
      </button>
    </div>
  );
};
