Implement sync service with exponential backoff:
```typescript
class SyncService {
  private syncInterval: NodeJS.Timer;
  private retryCount = 0;
  private maxRetries = 3;

  async startSync(userId: string) {
    // Initial sync
    await this.performSync(userId);

    // Set up polling (Gmail doesn't support webhooks for all operations)
    this.syncInterval = setInterval(async () => {
      try {
        await this.performSync(userId);
        this.retryCount = 0;
      } catch (error) {
        this.handleSyncError(error);
      }
    }, 30000); // 30 seconds
  }

  private async performSync(userId: string) {
    const lastSyncToken = await redis.get(`user:${userId}:syncToken`);
    const changes = await gmailService.getChanges(lastSyncToken);

    // Process changes and emit to connected clients via WebSocket
    await this.processChanges(changes);

    // Update sync token
    await redis.set(`user:${userId}:syncToken`, changes.newSyncToken);
  }

  private handleSyncError(error: Error) {
    if (this.retryCount < this.maxRetries) {
      const delay = Math.pow(2, this.retryCount) * 1000;
      setTimeout(() => this.performSync(userId), delay);
      this.retryCount++;
    } else {
      // Notify user of sync failure
      this.notifyUser('Sync failed after multiple attempts');
    }
  }
}
