Create Refresh component:
```typescript
const RefreshControl: React.FC = () => {
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [autoRefresh, setAutoRefresh] = useState(false);
  const [refreshInterval, setRefreshInterval] = useState(60);
  const queryClient = useQueryClient();

  useEffect(() => {
    if (autoRefresh) {
      const interval = setInterval(() => {
        queryClient.invalidateQueries(['emails']);
      }, refreshInterval * 1000);
      return () => clearInterval(interval);
    }
  }, [autoRefresh, refreshInterval]);

  const handleManualRefresh = async () => {
    setIsRefreshing(true);
    await queryClient.invalidateQueries(['emails']);
    setIsRefreshing(false);
  };

  return (
    <div className="refresh-control">
      <button 
        onClick={handleManualRefresh} 
        disabled={isRefreshing}
        className="refresh-button"
      >
        <span className={isRefreshing ? 'spinning' : ''}>↻</span>
        {isRefreshing ? 'Refreshing...' : 'Refresh'}
      </button>

      <div className="auto-refresh-toggle">
        <input 
          type="checkbox" 
          checked={autoRefresh} 
          onChange={(e) => setAutoRefresh(e.target.checked)}
        />
        <label>Auto-refresh every</label>
        <select 
          value={refreshInterval} 
          onChange={(e) => setRefreshInterval(Number(e.target.value))}
        >
          <option value={30}>30 seconds</option>
          <option value={60}>1 minute</option>
          <option value={300}>5 minutes</option>
        </select>
      </div>

      <span className="last-refresh">Last refresh: {formatTime(lastRefresh)}</span>
    </div>
  );
};
